{ title: "Koffie bestellen in Wenen", scene: "Je bent in een klassiek café in Wenen na een lange ochtend wandelen. Je wilt koffie bestellen en vraagt ook om iets zoets.", lines: [{ who: "them", de: "Guten Morgen, was möchten Sie?", nl: "Goedemorgen, wat wilt u graag?" }, { who: "you", de: "Guten Morgen, ich hätte gern einen Kaffee.", nl: "Goedemorgen, ik zou graag een koffie willen." }, { who: "them", de: "Mit Milch oder ohne Milch?", nl: "Met melk of zonder melk?" }, { who: "you", de: "Mit Milch, bitte.", nl: "Met melk, alstublieft." }, { who: "them", de: "Möchten Sie auch etwas essen?", nl: "Wilt u ook iets eten?" }, { who: "you", de: "Ja, was empfehlen Sie?", nl: "Ja, wat raadt u aan?" }, { who: "them", de: "Der Apfelstrudel ist sehr gut.", nl: "De apfelstrudel is erg goed." }, { who: "you", de: "Dann nehme ich den Apfelstrudel.", nl: "Dan neem ik de apfelstrudel." }, { who: "them", de: "Sehr gern. Noch etwas?", nl: "Heel graag. Nog iets?" }, { who: "you", de: "Nein danke, das ist alles.", nl: "Nee dank u, dat is alles." }, { who: "them", de: "Kommt sofort.", nl: "Komt er meteen aan." }] },
{ title: "Inchecken in een hotel in München", scene: "Je komt aan bij een hotel in München. Je hebt vooraf geboekt en wilt informatie over ontbijt en wifi.", lines: [{ who: "them", de: "Guten Abend, willkommen im Hotel.", nl: "Goedenavond, welkom in het hotel." }, { who: "you", de: "Guten Abend, ich möchte einchecken.", nl: "Goedenavond, ik wil graag inchecken." }, { who: "them", de: "Haben Sie eine Reservierung?", nl: "Heeft u een reservering?" }, { who: "you", de: "Ja, ich habe eine Reservierung auf den Namen Cannon.", nl: "Ja, ik heb een reservering op naam van Cannon." }, { who: "them", de: "Darf ich bitte Ihren Pass sehen?", nl: "Mag ik alstublieft uw paspoort zien?" }, { who: "you", de: "Ja, hier ist mein Pass.", nl: "Ja, hier is mijn paspoort." }, { who: "them", de: "Ihr Zimmer ist in der dritten Etage.", nl: "Uw kamer is op de derde verdieping." }, { who: "you", de: "Ist Frühstück inklusive?", nl: "Is ontbijt inbegrepen?" }, { who: "them", de: "Ja, Frühstück ist von sieben bis zehn Uhr.", nl: "Ja, ontbijt is van zeven tot tien uur." }, { who: "you", de: "Wie ist das WLAN-Passwort?", nl: "Wat is het wifiwachtwoord?" }, { who: "them", de: "Das Passwort steht auf der Karte.", nl: "Het wachtwoord staat op de kaart." }, { who: "you", de: "Danke schön.", nl: "Dank u wel." }] },
{ title: "De weg vragen in Berlijn", scene: "Je staat bij een druk plein in Berlijn en zoekt het dichtstbijzijnde metrostation. Je spreekt een voorbijganger beleefd aan.", lines: [{ who: "you", de: "Entschuldigung, wo ist die nächste U-Bahn?", nl: "Pardon, waar is de dichtstbijzijnde metro?" }, { who: "them", de: "Gehen Sie geradeaus und dann links.", nl: "Ga rechtdoor en dan links." }, { who: "you", de: "Ist es weit?", nl: "Is het ver?" }, { who: "them", de: "Nein, nur fünf Minuten zu Fuß.", nl: "Nee, maar vijf minuten te voet." }, { who: "you", de: "Welche Linie fährt zum Zentrum?", nl: "Welke lijn gaat naar het centrum?" }, { who: "them", de: "Nehmen Sie die Linie U2 Richtung Alexanderplatz.", nl: "Neem lijn U2 richting Alexanderplatz." }, { who: "you", de: "Muss ich umsteigen?", nl: "Moet ik overstappen?" }, { who: "them", de: "Nein, Sie können direkt fahren.", nl: "Nee, u kunt rechtstreeks gaan." }, { who: "you", de: "Vielen Dank für Ihre Hilfe.", nl: "Hartelijk dank voor uw hulp." }, { who: "them", de: "Kein Problem, gute Fahrt.", nl: "Geen probleem, goede reis." }] },
{ title: "Avondeten in Zürich", scene: "Je gaat naar een restaurant in Zürich zonder reservering. Je vraagt om een tafel, bekijkt de menukaart en bestelt een vegetarisch gerecht.", lines: [{ who: "them", de: "Guten Abend, haben Sie reserviert?", nl: "Goedenavond, heeft u gereserveerd?" }, { who: "you", de: "Nein, haben Sie einen Tisch frei?", nl: "Nee, heeft u een tafel vrij?" }, { who: "them", de: "Ja, für eine Person?", nl: "Ja, voor één persoon?" }, { who: "you", de: "Ja, für eine Person, bitte.", nl: "Ja, voor één persoon, alstublieft." }, { who: "them", de: "Hier ist die Speisekarte.", nl: "Hier is de menukaart." }, { who: "you", de: "Danke, ist dieses Gericht vegetarisch?", nl: "Dank u, is dit gerecht vegetarisch?" }, { who: "them", de: "Ja, das ist ohne Fleisch und ohne Fisch.", nl: "Ja, dat is zonder vlees en zonder vis." }, { who: "you", de: "Dann nehme ich dieses Gericht.", nl: "Dan neem ik dit gerecht." }, { who: "them", de: "Möchten Sie Wasser dazu?", nl: "Wilt u daar water bij?" }, { who: "you", de: "Ja, ein Wasser, bitte.", nl: "Ja, een water, alstublieft." }, { who: "them", de: "Sehr gern.", nl: "Heel graag." }, { who: "you", de: "Danke schön.", nl: "Dank u wel." }] },
{ title: "Een treinkaartje kopen in Hamburg", scene: "Je bent op het station in Hamburg en wilt een kaartje naar Lübeck kopen. Je vraagt naar prijs, perron en overstappen.", lines: [{ who: "them", de: "Guten Tag, wohin möchten Sie fahren?", nl: "Goedendag, waar wilt u naartoe reizen?" }, { who: "you", de: "Guten Tag, ich möchte nach Lübeck fahren.", nl: "Goedendag, ik wil naar Lübeck reizen." }, { who: "them", de: "Einfach oder hin und zurück?", nl: "Enkele reis of heen en terug?" }, { who: "you", de: "Hin und zurück, bitte.", nl: "Heen en terug, alstublieft." }, { who: "them", de: "Das kostet achtundzwanzig Euro.", nl: "Dat kost achtentwintig euro." }, { who: "you", de: "Kann ich mit Karte bezahlen?", nl: "Kan ik met kaart betalen?" }, { who: "them", de: "Ja, natürlich.", nl: "Ja, natuurlijk." }, { who: "you", de: "Von welchem Gleis fährt der Zug?", nl: "Van welk spoor vertrekt de trein?" }, { who: "them", de: "Von Gleis sechs.", nl: "Van spoor zes." }, { who: "you", de: "Muss ich umsteigen?", nl: "Moet ik overstappen?" }, { who: "them", de: "Nein, der Zug fährt direkt.", nl: "Nee, de trein rijdt rechtstreeks." }, { who: "you", de: "Danke, auf Wiedersehen.", nl: "Dank u, tot ziens." }] },
{ title: "Souvenirs kopen in Nürnberg", scene: "Je bent in een kleine souvenirwinkel in Nürnberg. Je zoekt een cadeau en vraagt naar prijs, kleuren en betalen met kaart.", lines: [{ who: "them", de: "Hallo, kann ich Ihnen helfen?", nl: "Hallo, kan ik u helpen?" }, { who: "you", de: "Ja, ich suche ein Geschenk.", nl: "Ja, ik zoek een cadeau." }, { who: "them", de: "Für wen ist das Geschenk?", nl: "Voor wie is het cadeau?" }, { who: "you", de: "Für einen Freund.", nl: "Voor een vriend." }, { who: "them", de: "Diese Tasse ist sehr beliebt.", nl: "Deze mok is erg populair." }, { who: "you", de: "Wie viel kostet sie?", nl: "Hoeveel kost die?" }, { who: "them", de: "Sie kostet zwölf Euro.", nl: "Die kost twaalf euro." }, { who: "you", de: "Haben Sie sie in einer anderen Farbe?", nl: "Heeft u die in een andere kleur?" }, { who: "them", de: "Ja, in Blau und Grün.", nl: "Ja, in blauw en groen." }, { who: "you", de: "Ich nehme die blaue Tasse.", nl: "Ik neem de blauwe mok." }, { who: "them", de: "Möchten Sie mit Karte bezahlen?", nl: "Wilt u met kaart betalen?" }, { who: "you", de: "Ja, bitte.", nl: "Ja, graag." }] },
{ title: "Bij de apotheek in Basel", scene: "Je voelt je niet lekker tijdens je reis en gaat naar een apotheek in Basel. Je legt je klacht uit en vraagt naar een middel zonder recept.", lines: [{ who: "them", de: "Guten Tag, was brauchen Sie?", nl: "Goedendag, wat heeft u nodig?" }, { who: "you", de: "Guten Tag, ich habe Kopfschmerzen.", nl: "Goedendag, ik heb hoofdpijn." }, { who: "them", de: "Haben Sie auch Fieber?", nl: "Heeft u ook koorts?" }, { who: "you", de: "Nein, kein Fieber.", nl: "Nee, geen koorts." }, { who: "them", de: "Brauchen Sie Tabletten?", nl: "Heeft u tabletten nodig?" }, { who: "you", de: "Ja, haben Sie etwas rezeptfrei?", nl: "Ja, heeft u iets zonder recept?" }, { who: "them", de: "Ja, diese Tabletten sind rezeptfrei.", nl: "Ja, deze tabletten zijn zonder recept." }, { who: "you", de: "Wie oft soll ich sie nehmen?", nl: "Hoe vaak moet ik ze nemen?" }, { who: "them", de: "Zweimal am Tag mit Wasser.", nl: "Twee keer per dag met water." }, { who: "you", de: "Danke, ich nehme sie.", nl: "Dank u, ik neem ze." }, { who: "them", de: "Gute Besserung.", nl: "Beterschap." }, { who: "you", de: "Danke schön.", nl: "Dank u wel." }] },
{ title: "Smalltalk met een local in Salzburg", scene: "Je zit op een bankje in Salzburg en raakt in gesprek met iemand uit de stad. Je praat over reizen, eten en lokale aanbevelingen.", lines: [{ who: "you", de: "Hallo, ist dieser Platz frei?", nl: "Hallo, is deze plek vrij?" }, { who: "them", de: "Ja, natürlich.", nl: "Ja, natuurlijk." }, { who: "you", de: "Danke, die Stadt ist sehr schön.", nl: "Dank u, de stad is erg mooi." }, { who: "them", de: "Sind Sie im Urlaub hier?", nl: "Bent u hier op vakantie?" }, { who: "you", de: "Ja, ich komme aus den Niederlanden.", nl: "Ja, ik kom uit Nederland." }, { who: "them", de: "Wie gefällt Ihnen Salzburg?", nl: "Hoe bevalt Salzburg u?" }, { who: "you", de: "Sehr gut, ich mag die Altstadt.", nl: "Heel goed, ik vind de oude stad leuk." }, { who: "them", de: "Dann sollten Sie auch die Festung besuchen.", nl: "Dan zou u ook de vesting moeten bezoeken." }, { who: "you", de: "Danke, das ist eine gute Empfehlung.", nl: "Dank u, dat is een goede aanbeveling." }, { who: "them", de: "Probieren Sie auch die lokalen Süßigkeiten.", nl: "Probeer ook de lokale zoetigheden." }, { who: "you", de: "Das mache ich gern.", nl: "Dat doe ik graag." }, { who: "them", de: "Viel Spaß in Salzburg.", nl: "Veel plezier in Salzburg." }] }
